#include<stdio.h>
int main()
{
    long long int n,k;
    scanf("%lld%lld",&n,&k);
    if(n==k||k==0){
        printf("0 0\n");
    }
    else if(k<=n/3){
        printf("1 %lld\n",2*k);
    }
    else if(k>n/3){
        printf("1 %lld\n",n-k);
    }
    return 0;
}

